import asyncio
import anthropic


async def run_parallel_tool_calls(
    client: anthropic.AsyncAnthropic,
    tool_blocks: list,
    tool_registry: dict,
) -> list[dict]:
    """Execute multiple tool calls concurrently instead of sequentially."""

    async def call_tool(block) -> dict:
        tool_fn = tool_registry.get(block.name)
        if tool_fn is None:
            return {
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": f"Error: tool '{block.name}' not registered",
                "is_error": True,
            }
        try:
            # If the tool is async, await it; otherwise run in executor
            if asyncio.iscoroutinefunction(tool_fn):
                result = await tool_fn(**block.input)
            else:
                loop = asyncio.get_event_loop()
                result = await loop.run_in_executor(None, lambda: tool_fn(**block.input))
            return {
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": str(result),
                "is_error": False,
            }
        except Exception as exc:
            return {
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": f"Tool error: {exc}",
                "is_error": True,
            }

    return await asyncio.gather(*[call_tool(b) for b in tool_blocks])
